extension Array {
    /// Truncates the array up to the specified index.
    ///
    /// This method mutates the original array, keeping the elements up to the given index (inclusive).
    /// If the index is out of bounds (negative, or greater than or equal to the array's count),
    /// the array remains unchanged.
    ///
    /// - Parameter index: The index up to which the array should be truncated.
    ///
    /// Example Usage:
    /// ```
    /// var numbers = [1, 2, 3, 4, 5]
    /// numbers.truncate(to: 2)
    /// // numbers is now [1, 2, 3] (elements at indices 0, 1, 2)
    /// ```
    mutating func truncate(to index: Int) {
        guard index >= 0 && index < self.count else {
            return
        }
        self = Array(self[..<(index + 1)])
    }
}

public extension Array where Element: Destination {
    /// Navigate back in the navigation stack by a specified number of destinations.
    ///
    /// - Parameter count: The number of destinations to navigate back by.
    /// If the count exceeds the number of destinations in the stack, the stack is emptied.
    mutating func navigateBack(_ count: Int = 1) {
        guard count > 0 else { return }
        guard count <= self.count else {
            self = .init()
            return
        }
        self.removeLast(count)
    }
    /// Navigate back to a specific destination in the stack, removing all destinations that come after it.
    ///
    /// - Parameter destination: The destination to navigate back to.
    /// If the destination does not exist in the stack, no action is taken.
    mutating func navigateBack(to destination: Element) {
        if let index = self.lastIndex(where: { $0 == destination }) {
            self.truncate(to: index)
        }
    }
    /// Resets the navigation stack to its initial state, effectively navigating to the root destination.
    mutating func navigateToRoot() {
        self = []
    }
    /// Appends a new destination to the navigation stack, moving forward in the navigation flow.
    ///
    /// - Parameter destination: The destination to navigate to.
    mutating func navigate(to destination: Element) {
        self.append(destination)
    }
    /// Appends multiple new destinations to the navigation stack.
    ///
    /// - Parameter destinations: An array of destinations to append to the navigation stack.
    mutating func navigate(to destinations: [Element]) {
        self += destinations
    }
    /// Replaces the current navigation stack with a new set of destinations.
    ///
    /// - Parameter destinations: An array of new destinations to set as the navigation stack.
    mutating func replace(with destinations: [Element]) {
        self = destinations
    }
}

public struct DestinationState<T: Destination>: DynamicProperty {
    @AppStorage private var storage: Data
    private let encoder: JSONEncoder = .init()
    private let decoder: JSONDecoder = .init()
    private let defaultValue: [T]
    public var wrappedValue: [T] {
        get {
            guard let decoded = try? decoder.decode([T].self, from: storage) else {
                return defaultValue
            }
            return decoded
        }
        nonmutating set {
            guard let encoded = try? encoder.encode(newValue) else { return }
            storage = encoded
        }
    }
    public var projectedValue: Binding<[T]> {
        Binding(
            get: { wrappedValue },
            set: { wrappedValue = $0 }
        )
    }
    public init(
        wrappedValue: [T],
        _ key: String = "DestinationStateKey",
        store: UserDefaults? = nil
    ) {
        defaultValue = wrappedValue
        let initialData = (try? encoder.encode(wrappedValue)) ?? Data()
        _storage = .init(wrappedValue: initialData, key, store: store)
    }
}

///   - DestinationType: The enum/struct you use to describe destinations.
///                Must conform to `Destination`.
///   - RootContent: The root view shown at the bottom of the stack.
public struct Navigator<DestinationType: Destination, RootContent: View>: View {
    @Binding private var path: [DestinationType]
    private let rootContent: () -> RootContent
    public init(
        path: Binding<[DestinationType]>,
        @ViewBuilder rootContent: @escaping () -> RootContent
    ) {
        self._path = path
        self.rootContent = rootContent
    }
    public var body: some View {
        NavigationStack(path: $path) {
            rootContent()
                .navigationDestination(for: DestinationType.self)
        }
    }
}

public extension View {
    /// Associates a destination view with a presented data type for use within a navigation stack.
    ///
    /// This is a convenience wrapper around the standard SwiftUI `navigationDestination(for:destination:)` modifier,
    /// tailored for use with types conforming to `Destination`. The destination view is the presented `Destination` instance itself.
    ///
    /// - Parameter destinationType: The type of `Destination` data that this destination binding supports.
    ///   This should be the metatype (e.g., `MyDestination.self`).
    /// - Returns: A view that has a navigation destination associated with the specified `Destination` data type.
    func navigationDestination<D: Destination>(for destinationType: D.Type) -> some View {
        self.navigationDestination(for: D.self, destination: { $0 })
    }
    /// Presents a sheet when a binding to an optional `Destination` item becomes non-nil.
    ///
    /// This is a convenience wrapper around the standard SwiftUI `sheet(item:onDismiss:content:)` modifier,
    /// tailored for use with types conforming to `Destination`. The content of the sheet is the item itself.
    ///
    /// - Parameters:
    ///   - item: A `Binding` to an optional `Destination` item. When `item` is non-nil,
    ///     the system passes the unwrapped item to the `content` closure, which then provides
    ///     the view for the sheet. If `item` becomes `nil`, the system dismisses the sheet.
    ///   - onDismiss: An optional closure that SwiftUI executes when the sheet dismisses.
    /// - Returns: A view that presents a sheet when the bound item is non-nil.
    func sheet<D: Destination & Identifiable>(item: Binding<D?>, onDismiss: (() -> Void)? = nil) -> some View {
        self.sheet(item: item, onDismiss: onDismiss, content: { $0 })
    }
}
